@app.route("/api/users/<user_id>", methods=["GET"])
@require_auth
def get_user(user_id):
    """Get a user by ID (tenant-scoped)."""
    current_user = request.current_user
    target_user = users_db.get(user_id)

    if target_user is None:
        return jsonify({"error": "not_found", "message": f"User '{user_id}' not found."}), 404

    # Tenant isolation
    if current_user["tenant_id"] != target_user["tenant_id"]:
        return jsonify({"error": "not_found", "message": f"User '{user_id}' not found."}), 404

    return jsonify({"user": target_user}), 200


@app.route("/api/users", methods=["GET"])
@require_auth
def list_users():
    """List all users in the current user's tenant."""
    current_user = request.current_user
    tenant_users = [
        u for u in users_db.values()
        if u["tenant_id"] == current_user["tenant_id"]
    ]
    return jsonify({"users": tenant_users, "count": len(tenant_users)}), 200


@app.route("/api/me", methods=["GET"])
@require_auth
def get_me():
    """Get the current authenticated user."""
    return jsonify({"user": request.current_user}), 200


